from manim import *

class Animation:
    def __init_subclass__(cls, **kwargs):
        # 自定义子类行为：在创建子类时打印一条信息
        super().__init_subclass__(**kwargs)
        print(f"A new subclass has been created: {cls.__name__}")

class MyAnimation(Animation):
    def __init__(self, mobject):
        super().__init__(mobject)

class InitSubclassExample(Scene):
    def construct(self):
        # 创建自定义动画对象
        mobject = Circle()
        anim = MyAnimation(mobject)

        # 添加并播放自定义动画
        self.add(mobject)
        self.play(anim)

from manim import *

class MyAnimation(Animation):
    @classmethod
    def set_default(cls, **kwargs):
        print("Setting default for MyAnimation")

class SetDefaultExample(Scene):
    def construct(self):
        # 设置自定义动画的默认值
        MyAnimation.set_default(run_time=2)

        # 创建动画对象并播放
        mobject = Square()
        anim = MyAnimation(mobject)
        self.add(mobject)
        self.play(anim)

